const body = $input.first().json.body || $input.first().json;
const onlyDigits = (s) => (s ? String(s).replace(/\D/g, '') : '');
const companies = body.companies || [];
const contacts = body.contacts || [];
const products = body.products || [];
const co = companies[0] || {};
const ct = contacts[0] || {};
const cnpj = onlyDigits(co.cnpj);
const isPJ = cnpj.length === 14;
const customer = {
  customer_name: co.name || ((ct.firstname || '') + ' ' + (ct.lastname || '')).trim() || 'Cliente HubSpot',
  customer_type: isPJ ? 'Company' : 'Individual',
  customer_group: 'Comercial',
  territory: 'Brazil',
  tax_id: isPJ ? cnpj : onlyDigits(co.cpf_responsavel),
  email_id: ct.email || '',
  mobile_no: ct.phone || ''
};
const prescribersMap = {};
const patients = [];
const items = [];
const fp_patients = [];
for (const p of products) {
  const item_code = p.sku;
  const qty = Number(p.quantity) || 0;
  items.push({ item_code, qty, rate: Number(p.price) || 0, sku: p.sku, item_name: p.name });
  for (const pat of (p.patients || [])) {
    const cpf = onlyDigits(pat.cpf);
    patients.push({ patient_name: pat.nome, cpf, birth_date: pat.data_nascimento || '', mobile: pat.telefone || '', address_line1: ((pat.endereco || '') + ' ' + (pat.numero || '')).trim(), city: pat.municipio || '', state: pat.uf || '', pincode: onlyDigits(pat.cep), neighborhood: pat.bairro || '', country: 'Brazil' });
    const crm = onlyDigits(pat.medico_crm);
    const key = crm + '-' + (pat.medico_uf || '');
    if (pat.medico_nome && !prescribersMap[key]) {
      prescribersMap[key] = { prescriber_name: pat.medico_nome, council_type: 'CRM', council_number: pat.medico_crm, council_state: pat.medico_uf, council_status: 'Ativo' };
    }
    fp_patients.push({ item_code, cpf, patient_name: pat.nome, qty: Number(pat.quantidade) || 0 });
  }
}
const prescribers = Object.values(prescribersMap);
return [{ json: { hubspot_deal_id: body.hubspot_deal_id || null, customer, prescribers, patients, items, fp_patients } }];

// Emite 1 item por prescritor (a partir do no Normalizar Payload).
// Se nao houver prescritores, emite 1 item vazio para nao quebrar o fluxo.
const data = $('Normalizar Payload').first().json;
const prescribers = data.prescribers || [];
if (prescribers.length === 0) {
  return [{ json: { _skip: true } }];
}
return prescribers.map(p => ({ json: p }));

// Emite 1 item por paciente (a partir do no Normalizar Payload).
const data = $('Normalizar Payload').first().json;
const patients = data.patients || [];
if (patients.length === 0) {
  return [{ json: { _skip: true } }];
}
// inclui um indice para reconciliar com fp_patients depois
return patients.map((p, i) => ({ json: Object.assign({ _idx: i }, p) }));

// Monta o body do Sales Order com items + fp_patients (doc 14, passo 3).
const data = $('Normalizar Payload').first().json;
const norm = data;

// Resolve o nome (ID) do Customer criado/existente.
let customerName = (norm.customer && norm.customer.customer_name) || null;
try {
  const cust = $('ERP - Upsert Customer').first().json;
  if (cust && cust.data && cust.data.name) customerName = cust.data.name;
} catch (e) {}

// Monta mapa cpf -> patient_id a partir das saidas do Upsert Patient.
const patItems = $('ERP - Upsert Patient').all();
const cpfToPatient = {};
const onlyDigits = (s) => (s ? String(s).replace(/\D/g, '') : '');
for (const it of patItems) {
  const j = it.json || {};
  const created = j.data || {};
  const cpf = onlyDigits(created.cpf || j.cpf);
  const pid = created.name || j.name;
  if (cpf && pid) cpfToPatient[cpf] = pid;
}

// Constroi fp_patients ligando cpf -> patient_id.
const fp_patients = (norm.fp_patients || []).map(fp => ({
  patient: cpfToPatient[onlyDigits(fp.cpf)] || null,
  item_code: fp.item_code,
  qty: fp.qty
}));

const items = (norm.items || []).map(i => ({ item_code: i.item_code, qty: i.qty, rate: i.rate }));

const today = new Date().toISOString().slice(0, 10);
const salesOrder = {
  doctype: 'Sales Order',
  customer: customerName,
  transaction_date: today,
  delivery_date: today,
  order_type: 'Sales',
  items: items,
  fp_patients: fp_patients
};

return [{ json: { sales_order_body: salesOrder, _customer: customerName, _hubspot_deal_id: norm.hubspot_deal_id || null } }];

