// Preparar Itens: emite 1 item por produto para upsert de Item no ERPNext
const norm = $('Normalizar Payload').first().json;
const items = norm.items || [];
const seen = {};
const out = [];
for (const it of items) {
  const code = String(it.item_code || it.sku || '').trim();
  if (!code || seen[code]) continue;
  seen[code] = true;
  out.push({ json: {
    item_code: code,
    item_name: it.item_name || code,
    item_group: 'Produtos',
    stock_uom: 'Unidade',
    is_stock_item: 0,
    is_sales_item: 1,
    is_purchase_item: 0
  } });
}
return out;

